#ifndef KERNEL_H
#define KERNEL_H

#include <cuda_fp16.h>
#include <cuda_runtime.h>
#include <stdint.h>

// Kernel function declarations
void launch_gemm_n256_k7168(
    const __half* A,
    const __half* B,
    __half* C,
    int M,
    int N,
    int K,
    cudaStream_t stream
);

#endif // KERNEL_H

#include "kernel.h"
#include <cuda_runtime.h>
#include <cstdio>

// Optimized block dimensions for A800 Tensor Cores
// Using 256 threads per block for better occupancy on A800
constexpr int TILE_M = 16;   // Rows per block
constexpr int TILE_N = 16;   // Cols per block (16 * 16 = 256 threads)
constexpr int TILE_K = 64;   // K dimension tiles

__global__ void gemm_n256_k7168_kernel(
    const __half* __restrict__ A,
    const __half* __restrict__ B,
    __half* __restrict__ C,
    int M,
    int N,
    int K
) {
    // Shared memory for tiles
    // As: [TILE_M, TILE_K] for A matrix tile
    // Bs: [TILE_K, TILE_N] for B matrix tile
    __shared__ __half As[TILE_M][TILE_K];
    __shared__ __half Bs[TILE_K][TILE_N];

    // Thread indices within block
    int tid = threadIdx.x;  // 0 to 255
    int tid_x = tid % TILE_N;  // 0 to TILE_N-1 (0-15)
    int tid_y = tid / TILE_N;  // 0 to TILE_M-1 (0-15)

    // Global output coordinates
    int row = blockIdx.y * TILE_M + tid_y;
    int col = blockIdx.x * TILE_N + tid_x;

    // Accumulator in float for better numerical precision
    float accum = 0.0f;

    // Loop over K dimension in tiles
    for (int k = 0; k < K; k += TILE_K) {
        // Load A tile into shared memory
        // Each thread loads one element from A
        // Thread (tid_y, tid_x) loads A[row, k + tid_x]
        int a_col = k + tid_x;
        if (row < M && a_col < K) {
            As[tid_y][tid_x] = A[row * K + a_col];
        } else {
            As[tid_y][tid_x] = __float2half(0.0f);
        }

        // Load B tile into shared memory
        // Each thread loads multiple elements to fill all TILE_K rows of Bs
        // Thread (tid_y, tid_x) loads B[col, k + i + tid_y] for i in 0..TILE_K/TILE_M
        for (int i = 0; i < TILE_K; i += TILE_M) {
            int b_k = k + i + tid_y;
            if (col < N && b_k < K) {
                Bs[i + tid_y][tid_x] = B[col * K + b_k];
            } else {
                Bs[i + tid_y][tid_x] = __float2half(0.0f);
            }
        }

        __syncthreads();

        // Compute partial products
        // Multiply A[row, k+i] * B[col, k+i] for all i in [0, TILE_K)
        // As[tid_y][i] = A[row, k+i]
        // Bs[i][tid_x] = B[col, k+i]
        #pragma unroll 8
        for (int i = 0; i < TILE_K; i += 8) {
            accum += __half2float(As[tid_y][i]) * __half2float(Bs[i][tid_x]);
            accum += __half2float(As[tid_y][i+1]) * __half2float(Bs[i+1][tid_x]);
            accum += __half2float(As[tid_y][i+2]) * __half2float(Bs[i+2][tid_x]);
            accum += __half2float(As[tid_y][i+3]) * __half2float(Bs[i+3][tid_x]);
            accum += __half2float(As[tid_y][i+4]) * __half2float(Bs[i+4][tid_x]);
            accum += __half2float(As[tid_y][i+5]) * __half2float(Bs[i+5][tid_x]);
            accum += __half2float(As[tid_y][i+6]) * __half2float(Bs[i+6][tid_x]);
            accum += __half2float(As[tid_y][i+7]) * __half2float(Bs[i+7][tid_x]);
        }

        __syncthreads();
    }

    // Write result
    if (row < M && col < N) {
        C[row * N + col] = __float2half(accum);
    }
}

void launch_gemm_n256_k7168(
    const __half* A,
    const __half* B,
    __half* C,
    int M,
    int N,
    int K,
    cudaStream_t stream
) {
    // Grid dimensions
    dim3 block(TILE_N * TILE_M);  // 256 threads per block
    dim3 grid((N + TILE_N - 1) / TILE_N, (M + TILE_M - 1) / TILE_M);

    // Launch kernel
    gemm_n256_k7168_kernel<<<grid, block, 0, stream>>>(A, B, C, M, N, K);
}

#include <torch/extension.h>
#include <ATen/ATen.h>
#include <ATen/cuda/CUDAContext.h>
#include "kernel.h"
#include <stdexcept>
#include <string>
#include <cstdio>

// Helper function to convert ScalarType to string
std::string scalar_type_to_string(torch::ScalarType dtype) {
    switch (dtype) {
        case torch::kFloat: return "float32";
        case torch::kHalf: return "float16";
        case torch::kBFloat16: return "bfloat16";
        case torch::kDouble: return "float64";
        case torch::kInt8: return "int8";
        case torch::kInt16: return "int16";
        case torch::kInt32: return "int32";
        case torch::kInt64: return "int64";
        case torch::kUInt8: return "uint8";
        case torch::kBool: return "bool";
        default: return "unknown";
    }
}

// Helper function to validate tensor properties
void validate_tensor(const torch::Tensor& tensor, const std::string& name, torch::DeviceType device_type, torch::ScalarType dtype) {
    if (!tensor.device().is_cuda()) {
        throw std::runtime_error(name + " must be on CUDA device");
    }
    if (tensor.dtype() != dtype) {
        throw std::runtime_error(name + " must have dtype " + scalar_type_to_string(dtype));
    }
    if (!tensor.is_contiguous()) {
        throw std::runtime_error(name + " must be contiguous");
    }
}

// Main run function - accepts 2 tensors (A, B) and returns C
torch::Tensor run(const torch::Tensor& A, const torch::Tensor& B) {
    // Validate inputs
    validate_tensor(A, "A", torch::kCUDA, torch::kHalf);
    validate_tensor(B, "B", torch::kCUDA, torch::kHalf);

    // Get dimensions
    int64_t M = A.size(0);
    int64_t K = A.size(1);
    int64_t N = B.size(0);

    // Validate dimensions match specification
    if (N != 256) {
        throw std::runtime_error("N dimension must be 256, got " + std::to_string(N));
    }
    if (K != 7168) {
        throw std::runtime_error("K dimension must be 7168, got " + std::to_string(K));
    }
    if (B.size(1) != K) {
        throw std::runtime_error("B's K dimension must match A's K dimension");
    }

    // Create output tensor C with shape [M, N]
    torch::Tensor C = torch::empty({M, N}, torch::TensorOptions().dtype(torch::kHalf).device(torch::kCUDA));

    // Get raw pointers - use at::Half for PyTorch tensors
    const at::Half* A_half_ptr = A.data_ptr<at::Half>();
    const at::Half* B_half_ptr = B.data_ptr<at::Half>();
    at::Half* C_half_ptr = C.data_ptr<at::Half>();

    // Convert to CUDA __half type for kernel call
    const __half* A_ptr = reinterpret_cast<const __half*>(A_half_ptr);
    const __half* B_ptr = reinterpret_cast<const __half*>(B_half_ptr);
    __half* C_ptr = reinterpret_cast<__half*>(C_half_ptr);

    // Get CUDA stream
    cudaStream_t stream = at::cuda::getCurrentCUDAStream();

    // Launch kernel
    launch_gemm_n256_k7168(A_ptr, B_ptr, C_ptr, static_cast<int>(M), static_cast<int>(N), static_cast<int>(K), stream);

    // Check for errors
    cudaError_t err = cudaGetLastError();
    if (err != cudaSuccess) {
        throw std::runtime_error("CUDA kernel execution error: " + std::string(cudaGetErrorString(err)));
    }

    return C;
}

// PYBIND11 module definition
PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("run", &run, "GEMM kernel execution function for A800 GPU");
}
